{"content": """"Mini CLI calculator."""
import argparse
import sys

def format_num(n):
    return f"{int(n)}" if n == int(n) else f"{n}"

def main():
    parser = argparse.ArgumentParser(description="Mini CLI calculator")
    subparsers = parser.add_subparsers(dest="command", required=True)

    for cmd in ["add", "sub", "mul", "div"]:
        sub = subparsers.add_parser(cmd)
        sub.add_argument("a", type=float)
        sub.add_argument("b", type=float)

    args = parser.parse_args()

    try:
        if args.command == "add":
            res = args.a + args.b
        elif args.command == "sub":
            res = args.a - args.b
        elif args.command == "mul":
            res = args.a * args.b
        elif args.command == "div":
            if args.b == 0:
                print("Error: Division by zero", file=sys.stderr)
                sys.exit(1)
            res = args.a / args.b

        print(format_num(res))
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)

if __name__ == "__main__":
    main()
